module top_module(decoder_F,
                  CBA);output reg [7:0] decoder_F;
input [2:0] CBA;
always @ (*)
  begin
    case (CBA)
      3'b000:
        decoder_F = 8'b11111110;
      3'b001:
        decoder_F = 8'b11111101;
      3'b010:
        decoder_F = 8'b11111011;
      3'b011:
        decoder_F = 8'b11110111;
      3'b100:
        decoder_F = 8'b11101111;
      3'b101:
        decoder_F = 8'b11011111;
      3'b110:
        decoder_F = 8'b10111111;
      3'b111:
        decoder_F = 8'b01111111;
    endcase
  end
endmodule
